215→    private fun updateInitialConnectionListSharingStatus() {
216→        if (isPostPublished()) {
217→            connections.map { it.isSharingEnabled = false }
218→            return
219→        }
220→        val shareLimitValue = shareLimit
221→        val skipConnections = postPublicizeSkipConnections()
222→        if (shareLimitValue is ShareLimit.Enabled) {
223→            // If shares remaining < number of connections, all connections are unchecked by default
224→            updateInitialConnectionListShareLimitEnabled(shareLimitValue, skipConnections)
225→        } else {
226→            updateInitialConnectionListShareLimitDisabled(skipConnections)
227→        }
228→    }
229→
230→    private fun updateInitialConnectionListShareLimitEnabled(
231→        shareLimitValue: ShareLimit.Enabled,
232→        skipConnections: List<PublicizeSkipConnection>
233→    ) {
234→        if (shareLimitValue.sharesRemaining < connections.size) {
235→            connections.map { it.isSharingEnabled = false }
236→        } else {
237→            connections.take(shareLimitValue.sharesRemaining).map {
238→                it.isSharingEnabled = true
239→            }
240→            connections.forEach { connection ->
241→                // Use metadata to verify if this connection was previously disabled by the user
242→                skipConnections.firstOrNull { it.connectionId() == connection.connectionId.toString() }
243→                    ?.let { connection.isSharingEnabled = it.isConnectionEnabled() }
244→            }
245→        }
246→    }
247→
248→    private fun updateInitialConnectionListShareLimitDisabled(skipConnections: List<PublicizeSkipConnection>) {
249→        // With share limit disabled we can enable all connections but still considering the skip
250→        // connections metadata
251→        connections.map { it.isSharingEnabled = true }
252→        connections.forEach { connection ->
253→            // Use metadata to verify if this connection was previously disabled by the user
254→            skipConnections.firstOrNull { it.connectionId() == connection.connectionId.toString() }
255→                ?.let { connection.isSharingEnabled = it.isConnectionEnabled() }
256→        }
257→    }
